    } else if (cache && cache.trdDd === trdDd && Array.isArray(cache.rows) && cache.rows.length) {
      krxCount = cache.rows.length;
      krxStatus = `ьКь OK (${krxCount}ъА)`;
    } else if (cache && Array.isArray(cache.rows) && cache.rows.length) {
      krxCount = cache.rows.length;
      krxStatus = `ьКь(ьЕъЗМ) ${krxCount}ъА (trdDd=${cache.trdDd || 'unknown'})`;
    } else {
      krxStatus = 'ьКь ьь (live probe ыЙэьБ)';
    }
  } catch (e) {
    krxStatus = 'ьээьИ ьЄэЈ: ' + String(e && e.message ? e.message : e);
  }

  const msg = `т [эЌьЄьВДэЌ] Autostock ьЄьМьЄыЌ ь ь\n- KST: ${today} ${timeKst}\n- KRX: ${krxStatus}`;

  try {
