  // Naver chart API v1: api.stock.naver.com (YYYYMMDDHHMMSS эь)
  const fetchDaily = async (code, startDate, endDate) => {
    // ы ьЇыЅМ YYYYMMDDHHMMSS эььМыЁ ыГэ (8ьыІЌыЉД 000000 ьЖъА)
