      }
    } catch (e) {}
    await sleep(300);
  }

  const resolveName = (d) => {
    const cached = store.naverNames && store.naverNames[d.code];
    if (cached && cached !== d.code && !isGarbled(cached)) return cached;
    if (d.name && d.name !== d.code && !isGarbled(d.name)) return d.name;
