  let msg = '[ьЃМъА ьЄь ьБъГМ ыІЌэЌэИ]' + NL +
    '№ ' + weekDates[0] + ' ~ ' + weekDates[weekDates.length - 1] + NL +
    'тттттттттттттттттттт' + NL +
    'ьДьЖьВ ' + recs.length + 'ъБД т ьЇь ' + enteredCount + 'ъБД т ьЙыЅ  ' + (evaluated.length > 0 ? (winRate * 100).toFixed(0) + '%' : 'N/A') + NL +
    'т ыЊЉэ ' + wins + 'ъБД т т ьь  ' + losses + 'ъБД т № ыГДь  ' + holdList.length + 'ъБД' + NL +
    'тттттттттттттттттттт' + NL;

  // т ььЕ ьЂыЊЉ
  if (winList.length > 0) {
    msg += NL + 'т ььЕ (' + winList.length + 'ъБД)' + NL;
    for (const d of winList) {
      const name = resolveName(d);
      let line = name + '(' + (d.code || '') + ') т ' + shortDate(d.date);
      if (Number.isFinite(d.maxReturn) && d.maxReturn !== 0) line += ' т ьЕъГ  ' + pct(d.maxReturn);
      if (d.hitTargetDay) line += ' ' + shortDate(d.hitTargetDay);
      if (d.score) line += ' т ' + d.score + 'ь ';
      msg += line + NL;
    }
  }

  // № ыГДь  ьЂыЊЉ
  if (holdList.length > 0) {
    msg += NL + '№ ыГДь  (' + holdList.length + 'ъБД)' + NL;
    for (const d of holdList) {
      const name = resolveName(d);
      let line = name + '(' + (d.code || '') + ') т ' + shortDate(d.date);
      if (Number.isFinite(d.maxReturn) && d.maxReturn !== 0) line += ' т ьЕъГ  ' + pct(d.maxReturn);
      if (d.result === 'holding' && d.exitDate) line += ' т ьь ьМ ' + shortDate(d.exitDate);
      if (d.result === 'expired') line += ' т ыГДь ьь ьМ ' + shortDate(d.exitDate || d.date);
      if (d.score) line += ' т ' + d.score + 'ь ';
      msg += line + NL;
    }
  }

  // т ьь  ьЂыЊЉ
  if (lossList.length > 0) {
    msg += NL + 'т ьь  (' + lossList.length + 'ъБД)' + NL;
    for (const d of lossList) {
      const name = resolveName(d);
      let line = name + '(' + (d.code || '') + ') т ' + shortDate(d.date);
      if (Number.isFinite(d.maxReturn) && d.maxReturn !== 0) line += ' т ьЕъГ  ' + pct(d.maxReturn);
      if (d.hitStopDay) line += ' т ьь  ' + shortDate(d.hitStopDay);
      if (d.score) line += ' т ' + d.score + 'ь ';
      msg += line + NL;
    }
  }

  // ыЇЄь ыЏИьЇь ьЂыЊЉ
  const notEnteredList = details.filter((d) => d.result === 'not_entered');
  if (notEnteredList.length > 0) {
    msg += NL + 'тЊ ыЇЄь ыЏИыыЌ (' + notEnteredList.length + 'ъБД)' + NL;
    for (const d of notEnteredList) {
      const name = resolveName(d);
      msg += name + '(' + (d.code || '') + ') т ' + shortDate(d.date) + NL;
    }
  }

  msg += NL + 'т яИ ыГИ ыІЌэЌэИы ьАИъГ ьЉьДыЉА эЌь ъВАъГМь ьБььЇьЇ ььЕыыЄ.';

  // Telegram 4096ь ьДъГМ ь ыЖыІЌ ь ьЁ
  const TELE_LIMIT = 4000;
  const chunks = [];
  if (msg.length <= TELE_LIMIT) {
    chunks.push(msg);
  } else {
    let remaining = msg;
    while (remaining.length > 0) {
      if (remaining.length <= TELE_LIMIT) { chunks.push(remaining); break; }
      let cut = remaining.lastIndexOf(NL, TELE_LIMIT);
      if (cut <= 0) cut = TELE_LIMIT;
      chunks.push(remaining.slice(0, cut));
      remaining = remaining.slice(cut).replace(/^\n/, '');
    }
  }

  for (let ci = 0; ci < chunks.length; ci++) {
    try {
      await http({ method: 'POST', url: 'https://api.telegram.org/bot' + BOT + '/sendMessage', json: true, body: { chat_id: CHAT, text: chunks[ci] } });
    } catch (e) {}
    if (ci < chunks.length - 1) await sleep(500);
  }

  return [{ json: { sent: true, count: recs.length, enteredCount, wins, losses, winRate } }];
};
