  const ACCOUNT_KRW = 10000000; // ь: 1,000ыЇь
  const RISK_PCT_PER_TRADE = 0.005; // ь: 0.5% (1э эИы ьДы ьЕы ььЄ эы)

  // ATR ъИАыА ьь /ыЊЉэъА(ыЈэы ъГМыэ э­ь ь э)
  const ATR_WINDOW = 14;
